import{_ as a,o as e,c as i,e as h}from"./app-4259075f.js";const r={},d=h('<h2 id="分类" tabindex="-1"><a class="header-anchor" href="#分类" aria-hidden="true">#</a> 分类</h2><h3 id="按照测试阶段分类" tabindex="-1"><a class="header-anchor" href="#按照测试阶段分类" aria-hidden="true">#</a> 按照测试阶段分类</h3><ul><li>单元测试: 单元测试是软件开发的第一步测试，目的是为了验证软件单元是否符合软件需求与设计。单元测试大多是开发人员进行的自测。</li><li>冒烟测试: 冒烟测试指软件构建版本建立后，对系统的基本功能进行简单的测试，这种测试重点验证的是程序的主要功能，而不会对具体功能进行深入测试。</li><li>集成测试: 集成测试是冒烟测试之后进行的测试，它是将已经测试过的软件单元组合在一起测试它们之间的接口，用于验证软件是否满足设计需求。</li><li>系统测试: 系统测试是将经过测试的软件在实际环境中运行，并与其他系统的成分（如数据库、硬件和操作人员等）组合在一起进行的测试。</li><li>验收测试: 验收测试主要是对软件产品说明进行验证，逐行逐字地按照说明书的描述对软件产品进行测试，确保其符合客户的各项要求。</li></ul><h3 id="按照测试技术分类" tabindex="-1"><a class="header-anchor" href="#按照测试技术分类" aria-hidden="true">#</a> 按照测试技术分类</h3><ul><li>黑盒测试: 黑盒测试就是把软件当作一个有输入与输出的黑匣子，把程序当作一个输入域到输出域的映射，只要输入的数据能输出预期的结果即可，不必关心程序内部是如何实现的</li><li>白盒测试: 白盒测试又叫透明盒测试，它是指测试人员了解软件程序的逻辑结构、路径与运行过程，在测试时，按照程序的执行路径得出结果。白盒测试就是把软件（程序）当作一个透明的盒子，测试人员清楚地知道从输入到输出的每一步过程。</li></ul><h3 id="按照软件质量特性分类" tabindex="-1"><a class="header-anchor" href="#按照软件质量特性分类" aria-hidden="true">#</a> 按照软件质量特性分类</h3><ul><li>功能测试: 功能测试就是测试软件的功能是否满足客户的需求，包括准确性、易用性、适合性、互操作性等。</li><li>性能测试: 性能测试就是测试软件的性能是否满足客户的需求，性能测试包括负载测试、压力测试、兼容性测试、可移植性测试和健壮性测试等。</li></ul><h2 id="软件测试模型" tabindex="-1"><a class="header-anchor" href="#软件测试模型" aria-hidden="true">#</a> 软件测试模型</h2><h3 id="v-模型" tabindex="-1"><a class="header-anchor" href="#v-模型" aria-hidden="true">#</a> V 模型</h3><h3 id="w-模型" tabindex="-1"><a class="header-anchor" href="#w-模型" aria-hidden="true">#</a> W 模型</h3><h3 id="h-模型" tabindex="-1"><a class="header-anchor" href="#h-模型" aria-hidden="true">#</a> H 模型</h3><h3 id="x-模型" tabindex="-1"><a class="header-anchor" href="#x-模型" aria-hidden="true">#</a> X 模型</h3>',12),l=[d];function t(n,c){return e(),i("div",null,l)}const o=a(r,[["render",t],["__file","test.html.vue"]]);export{o as default};
